  1	import type { FC } from 'react';
  2	import { Controller, useWatch } from 'react-hook-form';
  3	import { defaultStorageMapping, type StorageMapping } from 'src/storageMaps/constants';
  4	import { getSourceStorageValues } from 'src/storageMaps/utils/getSourceStorageValues';
  5	
  6	import { FormGroupWithHelpText } from '@components/common/FormGroupWithHelpText/FormGroupWithHelpText';
  7	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
  8	import type { ProviderVirtualMachine } from '@kubev2v/types';
  9	import { Alert, AlertVariant, Stack, StackItem, TextInput } from '@patternfly/react-core';
 10	import { isEmpty } from '@utils/helpers';
 11	import { useForkliftTranslation } from '@utils/i18n';
 12	
 13	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 14	import { useCreatePlanWizardContext } from '../../hooks/useCreatePlanWizardContext';
 15	import { useInitializeMappings } from '../../hooks/useInitializeMappings';
 16	import { GeneralFormFieldId } from '../general-information/constants';
 17	
 18	import { CreatePlanStorageMapFieldId, createPlanStorageMapFieldLabels } from './constants';
 19	import CreatePlanStorageMapFieldTable from './CreatePlanStorageMapFieldTable';
 20	
 21	const NewStorageMapFields: FC = () => {
 22	  const { t } = useForkliftTranslation();
 23	  const { control, getFieldState } = useCreatePlanFormContext();
 24	  const { storage, vmsWithDisks: vmsWithDisksResult } = useCreatePlanWizardContext();
 25	  const { error } = getFieldState(CreatePlanStorageMapFieldId.StorageMap);
 26	  const [sourceProvider, storageMap] = useWatch({
 27	    control,
 28	    name: [GeneralFormFieldId.SourceProvider, CreatePlanStorageMapFieldId.StorageMap],
 29	  });
 30	
 31	  const [availableSourceStorages, sourceStoragesLoading, sourceStoragesError] = storage.sources;
 32	  const [availableTargetStorages, _targetStoragesLoading, targetStoragesError] = storage.targets;
 33	  const [vmsWithDisks, vmsWithDisksLoading] = vmsWithDisksResult;
 34	
 35	  const isLoading = sourceStoragesLoading || vmsWithDisksLoading;
 36	
 37	  const { other: otherSourceStorages, used: usedSourceStorages } = getSourceStorageValues(
 38	    sourceProvider,
 39	    availableSourceStorages,
 40	    vmsWithDisks as ProviderVirtualMachine[],
 41	  );
 42	  const defaultTargetStorageName = availableTargetStorages?.[0]?.name;
 43	
 44	  useInitializeMappings<StorageMapping>({
 45	    currentMap: storageMap,
 46	    defaultTarget: defaultStorageMapping[CreatePlanStorageMapFieldId.TargetStorage],
 47	    defaultTargetName: defaultTargetStorageName,
 48	    fieldIds: {
 49	      mapField: CreatePlanStorageMapFieldId.StorageMap,
 50	      sourceField: CreatePlanStorageMapFieldId.SourceStorage,
 51	      targetField: CreatePlanStorageMapFieldId.TargetStorage,
 52	    },
 53	    isLoading,
 54	    usedSources: usedSourceStorages,
 55	  });
 56	
 57	  return (
 58	    <Stack hasGutter className="pf-v6-u-ml-lg">
 59	      {error?.root && <Alert variant={AlertVariant.danger} isInline title={error.root.message} />}
 60	
 61	      {isEmpty(usedSourceStorages) && !isLoading && (
 62	        <Alert
 63	          variant={AlertVariant.warning}
 64	          isInline
 65	          title={t('No source storages are available for the selected VMs.')}
 66	        />
 67	      )}
 68	
 69	      <CreatePlanStorageMapFieldTable
 70	        targetStorages={availableTargetStorages}
 71	        usedSourceStorages={usedSourceStorages}
 72	        otherSourceStorages={otherSourceStorages}
 73	        isLoading={isLoading}
 74	        loadError={sourceStoragesError ?? targetStoragesError}
 75	      />
 76	
 77	      <FormGroupWithHelpText
 78	        label={createPlanStorageMapFieldLabels[CreatePlanStorageMapFieldId.StorageMapName]}
 79	        helperText={t("Provide a name now, or we'll generate one when the map is created.")}
 80	        labelIcon={
 81	          <HelpIconPopover>
 82	            <Stack hasGutter>
 83	              <StackItem>
 84	                {t(
 85	                  'Your selected storage mappings will automatically save as a storage map when your plan is created.',
 86	                )}
 87	              </StackItem>
 88	              <StackItem>
 89	                {t(
 90	                  "Provide a name now, or we'll generate one when the map is created. You can find your storage maps under the Storage maps page.",
 91	                )}
 92	              </StackItem>
 93	            </Stack>
 94	          </HelpIconPopover>
 95	        }
 96	      >
 97	        <Controller
 98	          name={CreatePlanStorageMapFieldId.StorageMapName}
 99	          control={control}
100	          render={({ field }) => <TextInput {...field} />}
101	        />
102	      </FormGroupWithHelpText>
103	    </Stack>
104	  );
105	};
106	
107	export default NewStorageMapFields;

